  "id": "{{$timestamp}}",
  "method": "tools/call",
  "params": {
    "name": "madad_kyc_update_business_details",
    "arguments": {
      "access_token": "{{access_token}}",
      "legal_entity_name": "Acme Trading LLC",
      "cr_number": "123456",
