      "tax_reg_no": null,
      "tin_number": null,
      "business_city": "Doha",
      "business_country": "QA"
    }
  }
}

{
  "jsonrpc": "2.0",
  "id": "{{$timestamp}}",
  "method": "tools/call",
  "params": {
    "name": "madad_kyc_edit_buyer",
    "arguments": {
      "access_token": "{{access_token}}",
      "buyer_id": "{{buyer_id}}",
      "name": "Updated Corp Name",
      "cr_number": null,
      "contact_person": null,
      "contact_number": null,
      "contact_email": null,
      "buyer_type": null,
      "buyer_sector": null
    }
  }
}

{
  "jsonrpc": "2.0",
  "id": "{{$timestamp}}",
  "method": "tools/call",
  "params": {
    "name": "madad_payments_send_monetization_payment_link",
    "arguments": {
      "access_token": "{{access_token}}",
      "payment_id": "{{payment_id}}",
      "recipient_email": "{{email}}",
      "recipient_phone": null,
      "message_title": "Madad onboarding payment",
      "message_body": "Please complete your Madad onboarding and assessment fee payment using this secure link.",
      "idempotency_key": "{{idempotency_key}}"
    }
  }
}
